    it('should handle non-existent file gracefully', function(done) {
        const nonExistentPath = path.join(tempDir, 'nonexistent.db');
        const db = new dirty.Dirty(nonExistentPath);

        db.on('load', function(length) {
            assert.strictEqual(length, 0);
            assert.strictEqual(db.size(), 0);
            done();
        });
    });

    it('should emit drain event after all writes complete', function(done) {
        const db = new dirty.Dirty(dbPath);
        let drainEmitted = false;

        db.on('load', function() {
            db.on('drain', function() {
                drainEmitted = true;
                assert.strictEqual(drainEmitted, true);
                db.close();
                done();
            });

            db.set('test1', {value: 1});
            db.set('test2', {value: 2});
        });
    });
});
