        let db = new dirty.Dirty();

        // First set a value
        db.set('testKey', {data: 'exists'});
        assert.deepStrictEqual(db.get('testKey'), {data: 'exists'}, 'Data should exist initially');

        db.on('drain', function() {
            assert.strictEqual(db.get('testKey'), undefined, 'Data should be deleted');
            done();
        });

        // Then delete it by setting undefined
        db.set('testKey', undefined);
    });

