        let callbackCalled = false;

        db.on('load', function() {
            db.set('fileKey', {persistent: true}, function() {
                callbackCalled = true;
                assert.strictEqual(callbackCalled, true, 'Callback should be called');
                assert.deepStrictEqual(db.get('fileKey'), {persistent: true}, 'Data should be stored');
                done();
            });
        });
    });

    it('should handle multiple sets with file-based storage', function(done) {
        let db = new dirty.Dirty(tempFile);
        let callback1Called = false;
        let callback2Called = false;

        db.on('load', function() {
            db.set('key1', {value: 1}, function() {
                callback1Called = true;
            });

            db.set('key2', {value: 2}, function() {
                callback2Called = true;
                assert.strictEqual(callback1Called, true, 'First callback should be called');
                assert.strictEqual(callback2Called, true, 'Second callback should be called');
                assert.deepStrictEqual(db.get('key1'), {value: 1}, 'First data should be stored');
                assert.deepStrictEqual(db.get('key2'), {value: 2}, 'Second data should be stored');
                done();
            });
        });
